/// <summary>
///  Provides functionality to build parameter UI based on report metadata.
/// </summary>
class ETG_InventFairValuePostUIBuilder extends SrsReportDataContractUIBuilder
{
    ETG_InventFairValuePostContract     Contract;
    DialogField		availableCompanies;
    DialogField         valueField;
}

Method.Source:
public void postBuild()
{
    contract		    = this.dataContractObject() as ETG_InventFairValuePostContract;
    availableCompanies	= this.bindInfo().getDialogField(contract, methodStr(ETG_InventFairValuePostContract,  parmjournalName));
    availableCompanies .lookupButton(FormLookupButton::Always);
    valueField	= this.bindInfo().getDialogField(contract, methodstr(ETG_InventFairValuePostContract,parmAmount));
    valueField.enabled(false);
}

public void postRun()
{
    Query		        query		    = new Query();
    QueryBuildDataSource    qbdsLegalEntity     = query.addDataSource(tablenum(LedgerJournalTable));
    QueryBuildRange     qbr;

    qbdsLegalEntity.fields().addField(fieldNum(LedgerJournalTable,JournalName));
    //Add range to exclude blnak value
    qbr = qbdsLegalEntity.addRange(fieldNum(LedgerJournalTable, JournalName));
    qbr.value(SysQuery::valueNotEmptyString());// Exclude blank value
    qbdsLegalEntity.addGroupByField(fieldNum(LedgerJournalTable, JournalName));

    container selectedFields = [tableNum(LedgerJournalTable), fieldNum(LedgerJournalTable,JournalName)];
    SysLookupMultiSelectCtrl::constructWithQuery(this.dialog().dialogForm().formRun(), availableCompanies.control(), query, false, selectedFields);
}
